module bin_to_gray(
    input   [3:0]       bin_inverted,
    output  [3:0]       gray
);

// Binary to Gray code conversion logic
assign gray[3] = bin_inverted[3];
assign gray[2] = bin_inverted[3] ^ bin_inverted[2];
assign gray[1] = bin_inverted[2] ^ bin_inverted[1];
assign gray[0] = bin_inverted[1] ^ bin_inverted[0];

endmodule
